import re
hits = []
for page in data.get('pages', data if isinstance(data, list) else []):
    pno = page.get('page_number', page.get('page', '?'))
    txt = ''
    for el in page.get('elements', []):
        if isinstance(el, dict):
            txt += ' ' + (el.get('text','') or '')
